            { word: 'significant', ipa: '/sɪɡˈnɪfɪkənt/', pos: 'adj.', vi: 'quan trọng, đáng kể' },
            { word: 'like-minded', ipa: '/ˌlaɪk ˈmaɪndɪd/', pos: 'adj.', vi: 'cùng chí hướng' },
            { word: 'responsibly', ipa: '/rɪˈspɒnsəbli/', pos: 'adv.', vi: 'một cách có trách nhiệm' }
